/**
 * WebSocket Heartbeat Handler Tests
 * Validates ping/pong protocol, timeout handling, and graceful disconnection
 */

import { Socket } from 'socket.io';
import {
  attachHeartbeat,
  DEFAULT_HEARTBEAT_CONFIG,
  detachHeartbeat,
  getHeartbeatStats,
  HeartbeatConfig,
} from '../../websocket/handlers/heartbeat';

describe('Heartbeat Handler', () => {
  let mockSocket: Partial<Socket>;
  let eventHandlers: Record<string, Function[]>;

  beforeEach(() => {
    eventHandlers = {};
    mockSocket = {
      id: 'socket-123',
      connected: true,
      on: jest.fn((event: string, handler: Function) => {
        if (!eventHandlers[event]) {
          eventHandlers[event] = [];
        }
        eventHandlers[event].push(handler);
      }),
      emit: jest.fn(),
      removeAllListeners: jest.fn(),
      disconnect: jest.fn(),
    };

    jest.useFakeTimers();
  });

  afterEach(() => {
    jest.runOnlyPendingTimers();
    jest.useRealTimers();
  });

  describe('attachHeartbeat', () => {
    it('should initialize heartbeat state', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      expect(state.missedPongs).toBe(0);
      expect(state.isActive).toBe(true);
      expect(state.lastPingSent).toBeUndefined();
      expect(state.lastPongReceived).toBeUndefined();
    });

    it('should set up ping interval', () => {
      attachHeartbeat(mockSocket as Socket);

      jest.advanceTimersByTime(DEFAULT_HEARTBEAT_CONFIG.intervalMs);

      expect(mockSocket.emit).toHaveBeenCalledWith(
        'ping',
        expect.objectContaining({
          type: 'ping',
          version: 1,
        })
      );
    });

    it('should accept custom config', () => {
      const customConfig: Partial<HeartbeatConfig> = {
        intervalMs: 10000,
        timeoutMs: 2000,
      };

      attachHeartbeat(mockSocket as Socket, customConfig);

      jest.advanceTimersByTime(10000);

      expect(mockSocket.emit).toHaveBeenCalledWith('ping', expect.anything());
    });

    it('should handle pong responses', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      const pongHandler = eventHandlers['pong'][0];
      pongHandler({
        type: 'pong',
        version: 1,
        timestamp: new Date().toISOString(),
      });

      expect(state.missedPongs).toBe(0);
      expect(state.lastPongReceived).toBeDefined();
    });

    it('should reset missed pongs on pong', () => {
      const state = attachHeartbeat(mockSocket as Socket);
      state.missedPongs = 2;

      const pongHandler = eventHandlers['pong'][0];
      pongHandler({
        type: 'pong',
        version: 1,
        timestamp: new Date().toISOString(),
      });

      expect(state.missedPongs).toBe(0);
    });

    it('should increment missed pongs on timeout', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      const timeoutHandler = eventHandlers['ping-timeout'][0];
      timeoutHandler();

      expect(state.missedPongs).toBe(1);
    });

    it('should disconnect after max missed pongs', () => {
      const state = attachHeartbeat(mockSocket as Socket, {
        maxMissedPongs: 2,
      });

      const timeoutHandler = eventHandlers['ping-timeout'][0];

      timeoutHandler(); // 1st miss
      expect(state.isActive).toBe(true);

      timeoutHandler(); // 2nd miss
      expect(mockSocket.disconnect).toHaveBeenCalledWith(true);
      expect(state.isActive).toBe(false);
    });

    it('should not send pings when socket disconnected', () => {
      const state = attachHeartbeat(mockSocket as Socket);
      mockSocket.connected = false;

      jest.advanceTimersByTime(DEFAULT_HEARTBEAT_CONFIG.intervalMs);

      // Should not emit if socket not connected
      // (only initial setup call, not the interval call)
      const emitCalls = (mockSocket.emit as jest.Mock).mock.calls.length;
      expect(emitCalls).toBe(0);
    });

    it('should not send pings when heartbeat inactive', () => {
      const state = attachHeartbeat(mockSocket as Socket);
      state.isActive = false;

      jest.advanceTimersByTime(DEFAULT_HEARTBEAT_CONFIG.intervalMs);

      const emitCalls = (mockSocket.emit as jest.Mock).mock.calls.length;
      expect(emitCalls).toBe(0);
    });
  });

  describe('detachHeartbeat', () => {
    it('should stop sending heartbeats', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      detachHeartbeat(mockSocket as Socket, state);

      jest.advanceTimersByTime(DEFAULT_HEARTBEAT_CONFIG.intervalMs * 5);

      // Emit should only be called in setup, not in intervals after detach
      expect(mockSocket.emit).not.toHaveBeenCalledWith('ping', expect.anything());
    });

    it('should mark heartbeat as inactive', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      detachHeartbeat(mockSocket as Socket, state);

      expect(state.isActive).toBe(false);
    });

    it('should clear all event listeners', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      detachHeartbeat(mockSocket as Socket, state);

      expect(mockSocket.removeAllListeners).toHaveBeenCalledWith('pong');
      expect(mockSocket.removeAllListeners).toHaveBeenCalledWith('ping-timeout');
    });
  });

  describe('getHeartbeatStats', () => {
    it('should return current heartbeat statistics', () => {
      const state = attachHeartbeat(mockSocket as Socket);
      const now = new Date();
      state.lastPingSent = now;
      state.lastPongReceived = new Date(now.getTime() + 100);
      state.missedPongs = 1;

      const stats = getHeartbeatStats(state);

      expect(stats).toEqual({
        isActive: true,
        lastPingSent: now.toISOString(),
        lastPongReceived: state.lastPongReceived.toISOString(),
        missedPongs: 1,
        estimatedLatencyMs: 100,
      });
    });

    it('should handle undefined timestamps', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      const stats = getHeartbeatStats(state);

      expect(stats.lastPingSent).toBeUndefined();
      expect(stats.lastPongReceived).toBeUndefined();
      expect(stats.estimatedLatencyMs).toBeUndefined();
    });

    it('should calculate latency correctly', () => {
      const state = attachHeartbeat(mockSocket as Socket);
      const now = new Date();
      state.lastPingSent = now;
      state.lastPongReceived = new Date(now.getTime() + 250);

      const stats = getHeartbeatStats(state);

      expect(stats.estimatedLatencyMs).toBe(250);
    });
  });

  describe('Integration Scenarios', () => {
    it('should handle normal ping-pong cycle', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      // First ping sent
      jest.advanceTimersByTime(DEFAULT_HEARTBEAT_CONFIG.intervalMs);

      // Simulate pong response
      const pongHandler = eventHandlers['pong'][0];
      pongHandler({
        type: 'pong',
        version: 1,
        timestamp: new Date().toISOString(),
      });

      expect(state.missedPongs).toBe(0);
      expect(state.lastPongReceived).toBeDefined();
    });

    it('should recover from single missed pong', () => {
      const state = attachHeartbeat(mockSocket as Socket);

      // First cycle: ping sent, times out
      jest.advanceTimersByTime(DEFAULT_HEARTBEAT_CONFIG.intervalMs);
      const timeoutHandler = eventHandlers['ping-timeout'][0];
      timeoutHandler();
      expect(state.missedPongs).toBe(1);

      // Second cycle: pong received, resets
      jest.advanceTimersByTime(DEFAULT_HEARTBEAT_CONFIG.intervalMs);
      const pongHandler = eventHandlers['pong'][0];
      pongHandler({
        type: 'pong',
        version: 1,
        timestamp: new Date().toISOString(),
      });

      expect(state.missedPongs).toBe(0);
    });

    it('should escalate missed pongs until disconnect', () => {
      const state = attachHeartbeat(mockSocket as Socket, {
        maxMissedPongs: 3,
      });

      const timeoutHandler = eventHandlers['ping-timeout'][0];

      // Miss 1
      timeoutHandler();
      expect(state.missedPongs).toBe(1);
      expect(mockSocket.disconnect).not.toHaveBeenCalled();

      // Miss 2
      timeoutHandler();
      expect(state.missedPongs).toBe(2);
      expect(mockSocket.disconnect).not.toHaveBeenCalled();

      // Miss 3 - disconnect
      timeoutHandler();
      expect(state.missedPongs).toBe(3);
      expect(mockSocket.disconnect).toHaveBeenCalledWith(true);
      expect(state.isActive).toBe(false);
    });
  });
});
